{
  "terms": [
    {
      "term": "Transmission Voltages",
      "simpleDefinition": "The specific high-voltage levels used to move electricity efficiently over long distances across the UK.",
      "anchor": "400 kV, 275 kV, and 132 kV.",
      "misconception": "Confusing these with lower distribution voltages like 11 kV or 230 V."
    },
    {
      "term": "Large-Scale Generation",
      "simpleDefinition": "Centralized power stations that produce massive amounts of electricity to supply the national network.",
      "anchor": "Nuclear, gas, and coal power stations.",
      "misconception": "Believing that all renewable energy sources are small-scale or 'micro'."
    },
    {
      "term": "Micro-generation",
      "simpleDefinition": "Small-scale production of electricity or heat, usually generated at the point where it is used.",
      "anchor": "Solar panels on a house roof or a small domestic wind turbine.",
      "misconception": "Assuming micro-generation is intended to power the entire national grid independently."
    },
    {
      "term": "Photovoltaic (PV)",
      "simpleDefinition": "A method of generating electricity directly from sunlight using specialized solar cells.",
      "anchor": "Solar PV panels.",
      "misconception": "Confusing PV (which makes electricity) with solar thermal panels (which only heat water)."
    },
    {
      "term": "Biomass",
      "simpleDefinition": "Generating electricity by burning organic materials, such as wood pellets, crops, or animal waste.",
      "anchor": "Burning wood chips in a specialized power plant.",
      "misconception": "Thinking biomass is a fossil fuel like coal; it is actually considered a renewable or carbon-neutral source."
    },
    {
      "term": "Hydro-electric",
      "simpleDefinition": "Generating electricity by using the force of falling or flowing water to turn a turbine.",
      "anchor": "Large dams or mountain reservoirs.",
      "misconception": "Thinking hydro-power is only available from the sea; it mostly comes from inland rivers and lakes."
    },
    {
      "term": "Transmission Efficiency",
      "simpleDefinition": "The practice of using very high voltages to reduce the amount of energy lost as heat during transport.",
      "anchor": "High voltage = Low current = Low heat loss.",
      "misconception": "Thinking high voltage is used because it travels 'faster' rather than to reduce energy waste."
    }
  ],
  "anchorPhrases": [
    "UK transmission voltages are 400 kV, 275 kV, and 132 kV.",
    "High voltage is used for transmission to minimize heat loss (I²R loss).",
    "Micro-generation happens at the point of consumption.",
    "Large-scale generation feeds the National Grid."
  ],
  "misconceptionTargets": [
    "The belief that 11 kV is a transmission voltage.",
    "The idea that high voltage is used because it is 'stronger' rather than for efficiency.",
    "Confusing domestic solar PV with large-scale power station generation."
  ]
}

